/*—— 分割线 ——*/
hr {
    all: unset !important; 
    display: block !important;
    visibility: visible !important;
    background-image: none !important; 
    height: auto !important; 
    min-height: unset !important;
    margin: 0 !important;
    opacity: 1 !important;
    position: relative;
}
hr::after {
    content: "" !important;
    display: block !important;
    background-image: var(--divider-image, url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=")) !important; /* 👁分割线图片 */
    background-repeat: no-repeat !important;
    background-position: var(--divider-position, center) !important;
    background-size: var(--divider-size, auto 100%) !important; 
    height: var(--divider-heig9ht, 89px) !important; /* 大小 */
    width: var(--divider-width, 100%) !important; /* 宽 */
    margin: var(--divider-margin, 0px 0) !important; /* 边距 */
    opacity: var(--divider-opacity, 1) !important; /* 透明度控制 */
}


/*—— 输入框提示词编辑（感谢墨千尾老师） ——*/

#nonQRFormItems {
    position: relative;
}
#send_textarea::placeholder {
    color: transparent !important;
    text-shadow: none !important; 
}
#nonQRFormItems:has(#send_textarea:placeholder-shown)::before {
    content: "PUBLISH A REWARD";
    color: #bcbcbc; /* 颜色 */
    left: 110px; /* 左右 */
    position: absolute; 
    top: 54%; /* 上下 */
    transform: translateY(-50%); 

    font-style: oblique; /* 字体样式：可以改为 normal (正常) 或 oblique (倾斜) */
    font-size: 0.5em;  /* 字体大小 */
    pointer-events: none; 
    z-index: 10; 
    white-space: nowrap; 
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: calc(100% - 30px); 
}





