/*——————复选——————*/

/* 复选框基底 - 日间模式 */
input[type='checkbox'] {
  width: 18px;
  height: 18px;
  background: rgba(19, 19, 19, 1);
  box-shadow: 
    inset 1px 1px 2px rgba(55, 55, 55, 0.9),
    2px 2px 5px rgba(195, 195, 195, 0.8),
    0 0 0 1px #525252,
    0 0 0 2px #000000,
    0 0 0 3px #525252;
  border-radius: 3px;
  transition: all 0.2s ease;
}

/* 悬停状态 */
input[type='checkbox']:hover {
  background: rgba(119, 119, 119, 0.98);
  box-shadow: 
    inset -1px -1px 3px rgba(195, 195, 195, 0.5),
    2px 2px 4px rgba(195, 195, 195, 0.3),
    0 0 0 1px #F5F5F5,
    0 0 0 2px #B8B8B8,
    0 0 0 3px #FAFAFA;
}

/* 选中状态 */
input[type='checkbox']:checked {
  background: #3d3d3d;
  box-shadow: 
    inset 1px 1px 7px rgba(0, 0, 0, 0.2),
    1px px 3px rgba(0, 0, 0, 0.8),
    0 0 0 1px #EAEAEA,
    0 0 0 2px #FFFFFF,
    0 0 0 3px #C4C4C4;
}

/* 选中图标 */
input[type='checkbox']:checked::after {
  content: '-';
  font-size: 18px;
  font-weight: 600;
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  color: #ffffff;
  text-shadow: 0 0 5px rgba(0, 0, 0, 1);
}

/* 👁不可删👁勾选隐藏 */
input[type="checkbox"]::before {
  content: none !important;
}



