  background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/cover, #ffffff;
  border: 1px solid #1f1f1f;
  border-radius: 0px;
  box-shadow: 
    inset 2px 2px 4px rgba(0, 0, 0, 0),
    2px 2px 7px rgba(0, 0, 0, 0.4);
  color: #8b8b8b;
  padding: 0px 12px;
  transition: all 0.3s ease;
  height: 20px;
  font-size: 11px;
}

.drawer-content select:hover {
  box-shadow: 
    inset -2px -2px 4px rgba(0, 0, 0, 0.15),
    3px 3px 8px rgba(0, 0, 0, 0.15);
}

.drawer-content select:focus {
  box-shadow: 
    inset 2px 2px 4px rgba(0, 0, 0, 0.7),
    0 0 0 1px rgba(0, 0, 0, 0.2),
    3px 3px 8px rgba(0, 0, 0, 0.35);
}

/* ===== 输入框 ===== */
input:not([type="file" i], [type="image" i], [type="checkbox" i], [type="radio" i]) {
  background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/cover, #ffffff;
  border: 1px solid #000000;
  border-radius: 0px;
  box-shadow: 
    inset 0px 4px 7px rgba(0, 0, 0,, 0.4),
    2px 2px 6px rgba(0, 0, 0, 0.4);
  color: #00000;
  padding: 10px 14px;
  height: 15px;
  font-size: 10px;
  transition: all 0.25s ease;

}

input:focus {
  box-shadow: 
    inset -2px -2px 4px rgba(195, 195, 195, 0.15),
    0 0 0 1px rgba(195, 195, 195, 0.2),
    2px 2px 6px rgba(195, 195, 195, 0.15);
}

input:hover {
  box-shadow: 
    inset -2px -2px 4px rgba(195, 195, 195, 0.15),
    3px 3px 8px rgba(195, 195, 195, 0.15);
}

input:disabled {
  background: url('') center/cover, #f0f0f0;
  color: #a0a0a0;
  box-shadow: 2px 2px 4px rgba(195, 195, 195, 0.1);
}

/* ===== 文本框 ===== */
.text_pole {
  background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/cover, #ffffff;
  border: 1px solid #000000;
  border-radius: 8px;
  box-shadow: 
    inset 2px 2px 6px rgba(195, 195, 195, 0),
    2px 2px 6px rgba(195, 195, 195, 0);
  color: #8b8b8b;
  padding: 10px;
  transition: all 0.3s ease;
font-weight: 500;
    letter-spacing: 0.2px;
    font-size: 11px;
}

.text_pole:focus {
  box-shadow: 
    inset 2px 2px 4px rgba(195, 195, 195, 0),
    0 0 0 1px rgba(195, 195, 195, 0),
