}

/* ===== 预设 ===== */
#completion_prompt_manager #completion_prompt_manager_list {
  background: url('') center/cover, rgba(0, 0, 0, 0.85);
  border: 1px solid #000000;
  border-radius: 8px;
  box-shadow: 
    inset -2px -2px 4px rgba(0, 0, 0, 0.15),
    2px 2px 8px rgba(0, 0, 0, 0.15);
  color: #bcbcbc;
}

#completion_prompt_manager_list::-webkit-scrollbar-thumb {
  background: rgba(195, 195, 195, 0.3);
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt {
    align-items: center;
    padding: 0.5em;
    border: 2px solid #242424;
    background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/cover, #ffffff;
    border-radius: 0px;
    box-shadow: 
        inset 2px 2px 7px rgba(0, 0, 0, 0),
        2px 2px 6px rgba(0, 0, 0, 0.4);
    margin-bottom: 10px;
    transition: all 0.2s ease;
}

#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt.completion_prompt_manager_prompt_disabled {
    background: url('') center/cover, #0d0d0d;
    border: 1px solid #000000;
    box-shadow: 2px 2px 4px rgba(0, 0, 0, 0.1);
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt:hover {
    box-shadow: 
        inset -2px -2px 4px rgba(0, 0, 0, 0.5),
        3px 3px 8px rgba(0, 0, 0, 0.5);
}
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt span span span {
    filter: none; /* 移除开关阴影 */
}
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt {
    position: relative;
    overflow: visible;
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt::before {
    content: "";
    position: absolute;
    width: 55px;
    height: 55px;
    background-image: url('');
    background-size: contain;
    background-repeat: no-repeat;
    z-index: 10;
    pointer-events: none;
    top: -20px;
    right: 75px;
    transform: rotate(15deg);
}
