/*加载更多消息*/
#show_more_messages {
    text-align: center;
    margin: 28px auto;
    font-weight: 500;
    order: -1;
    cursor: pointer;
    padding: 0.5em 1em;
    background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/cover, #ffffff;
    width: fit-content;
    border-radius: 0px;
    border: 2px solid #1f1f1f;
    box-shadow: 2px 2px 5px rgba(0, 0, 0, 0.2),
                inset 2px 2px 4px rgba(0, 0, 0, 0.5),
                inset 2px 2px 4px rgba(0, 0, 0,0);
    color: transparent;
    position: relative;
    display: block; 
    z-index: 10; 
    min-height: 20px; 
}

#show_more_messages::after {
    content: "過往通緝";
    color: #8b8b8b;
    position: absolute;
    left: 0;
    right: 0;
    top: 0;
    bottom: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    pointer-events: none; 
}
